24	        throw std::runtime_error("ERROR: Cannot open data file: " + filename);
25	    }
26	
27	    std::vector<std::vector<int8_t>> data;
28	    std::string line;
29	
30	    while (std::getline(infile, line)) {
31	        std::istringstream iss(line);
32	        std::vector<int8_t> row;
33	        int8_t value;
34	        int tmp;
35	        while (iss >> tmp) row.push_back(static_cast<int8_t>(tmp));
36	
37	        if (!row.empty()) {
38	            data.push_back(row);
39	        }
40	    }
41	
42	    return data;
