46	int main(int argc, char* argv[]) {
47	    // TARGET_DEVICE macro needs to be passed from gcc command line
48	    if (argc < 2 || argc > 3) {
49	        std::cout << "ERROR: Usage: " << argv[0] << " <xclbin> [data_file]" << std::endl;
50	        return EXIT_FAILURE;
51	    }
52	
53	    std::string xclbinFilename = argv[1];
54	    std::cout << "INFO: Running decode kernel " << xclbinFilename << std::endl;
55	
56	    bool dataFileLoaded = false;                // Flag for whether data file is loaded
57	    std::vector<std::vector<int8_t>> file_data;       // Storage for loaded data
58	    // Load feature maps output data from file if provided
59	    if (argc == 3) {
60	        std::string data_file = argv[2];
61	        try {
62	            file_data = loadDataFile(data_file);
63	            dataFileLoaded = true;
64	            std::cout << "INFO: Loaded " << file_data.size() << " arrays from file: " << data_file << std::endl;
65	
66	        } catch (const std::exception& e) {
67	            std::cerr << "ERROR: " << e.what() << std::endl;
68	            return EXIT_FAILURE;
69	        }
70	    } else {
71	        std::cout << "INFO: No data file provided" << std::endl;
72	    }
73	
74	    // Compute the size of array in bytes
75	    size_t big_int_size_in_bytes = MAX_FEATURE_SIZE * sizeof(int8_t);
76	    size_t int_size_in_bytes = DATA_SIZE * sizeof(int);
77	    size_t float_size_in_bytes = DATA_SIZE * sizeof(float);
78	    size_t pragma_int_size_in_bytes = 16 * sizeof(int);
79	    size_t pragma_float_size_in_bytes = 16 * sizeof(float);
80	
81	    std::vector<cl::Device> devices;
82	    cl_int err;
83	    cl::Context context;
84	    cl::CommandQueue q;
85	    cl::Kernel krnl_decode;
86	    cl::Program program;
87	    std::vector<cl::Platform> platforms;
88	    bool found_device = false;
89	    bool profile_cl = false;
90	    cl::Event evt_write;   // host -> device copy (migrate in)
91	    cl::Event evt_kernel;  // kernel run
92	    cl::Event evt_read;    // device -> host copy (migrate out)
93	    cl_int prof_err;
94	
95	    // traversing all Platforms To find Xilinx Platform and targeted
96	    // Device in Xilinx Platform
97	    cl::Platform::get(&platforms);
98	    for (size_t i = 0; (i < platforms.size()) && (found_device == false); i++) {
99	        cl::Platform platform = platforms[i];
100	        std::string platformName = platform.getInfo<CL_PLATFORM_NAME>();
101	        if (platformName == "Xilinx") {
102	            devices.clear();
103	            platform.getDevices(CL_DEVICE_TYPE_ACCELERATOR, &devices);
104	            if (devices.size()) {
105	                found_device = true;
106	                break;
107	            }
108	        }
109	    }
110	    if (found_device == false) {
111	        std::cout << "Error: Unable to find Target Device " << std::endl;
112	        return EXIT_FAILURE;
113	    }
114	
115	    std::cout << "INFO: Reading " << xclbinFilename << std::endl;
116	    FILE* fp;
117	    if ((fp = fopen(xclbinFilename.c_str(), "r")) == nullptr) {
118	        printf("ERROR: %s xclbin not available please build\n", xclbinFilename.c_str());
119	        exit(EXIT_FAILURE);
120	    }
121	    // Load xclbin
122	    std::cout << "Loading: '" << xclbinFilename << "'\n";
123	    std::ifstream bin_file(xclbinFilename, std::ifstream::binary);
124	    bin_file.seekg(0, bin_file.end);
125	    unsigned nb = bin_file.tellg();
126	    bin_file.seekg(0, bin_file.beg);
127	    char* buf = new char[nb];
128	    bin_file.read(buf, nb);
129	
130	    // Creating Program from Binary File
131	    cl::Program::Binaries bins;
132	    bins.push_back({buf, nb});
133	    bool valid_device = false;
134	    for (unsigned int i = 0; i < devices.size(); i++) {
135	        auto device = devices[i];
136	        // Creating Context and Command Queue for selected Device
137	        OCL_CHECK(err, context = cl::Context(device, nullptr, nullptr, nullptr, &err));
138	        OCL_CHECK(err, q = cl::CommandQueue(context, device, CL_QUEUE_PROFILING_ENABLE, &err));
139	        std::cout << "Trying to program device[" << i << "]: " << device.getInfo<CL_DEVICE_NAME>() << std::endl;
140	        cl::Program program(context, {device}, bins, nullptr, &err);
141	        if (err != CL_SUCCESS) {
142	            std::cout << "Failed to program device[" << i << "] with xclbin file!\n";
143	        } else {
144	            std::cout << "Device[" << i << "]: program successful!\n";
145	            OCL_CHECK(err, krnl_decode = cl::Kernel(program, "decode_krnl", &err));
146	            valid_device = true;
147	            break; // we break because we found a valid device
148	        }
149	    }
150	    if (!valid_device) {
151	        std::cout << "Failed to program any device found, exit!\n";
152	        exit(EXIT_FAILURE);
153	    }
154	
155	    const int num_layers   = 4;
156	    const int num_classes  = 3;
157	    const int output_dim   = num_classes + 64;
158	    const float conf_thresh = 0.25f;
159	    const int max_boxes_num = 2048;
160	    const int feat_layer_sizes[num_layers] = {200, 100, 50, 25};
161	    const float feat_layer_strides[num_layers] = {4.0f, 8.0f, 16.0f, 32.0f};
162	
163	    // Input buffers
164	    OCL_CHECK(err, cl::Buffer input_data(context, CL_MEM_READ_ONLY, big_int_size_in_bytes, NULL, &err));
165	    OCL_CHECK(err, cl::Buffer layer_size(context, CL_MEM_READ_ONLY, pragma_int_size_in_bytes, NULL, &err));
166	    OCL_CHECK(err, cl::Buffer layer_stride(context, CL_MEM_READ_ONLY, pragma_float_size_in_bytes, NULL, &err));
167	
168	    // Output return buffer
169	    OCL_CHECK(err, cl::Buffer out_boxes_x(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
170	    OCL_CHECK(err, cl::Buffer out_boxes_y(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));    
171	    OCL_CHECK(err, cl::Buffer out_boxes_w(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
172	    OCL_CHECK(err, cl::Buffer out_boxes_h(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
173	    OCL_CHECK(err, cl::Buffer out_cls(context, CL_MEM_WRITE_ONLY, int_size_in_bytes, NULL, &err));
174	    OCL_CHECK(err, cl::Buffer out_score(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
175	    OCL_CHECK(err, cl::Buffer out_box_num(context, CL_MEM_WRITE_ONLY, int_size_in_bytes, NULL, &err));
176	    
177	    // // set the kernel Arguments
178	    int narg = 0;
179	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, input_data));
180	    // OCL_CHECK(err, err = krnl_decode.setArg(narg++, layer_size));
181	    // OCL_CHECK(err, err = krnl_decode.setArg(narg++, layer_stride));
182	    int layer_size_arg_index = narg++;      // remember index for layer_size
183	    int layer_stride_arg_index = narg++;    // remember index for layer_stride
184	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_x));    
185	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_y));  
186	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_w));    
187	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_h));  
188	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_cls));    
189	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_score));    
190	    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_box_num));
191	
192	    // We then need to map our OpenCL buffers to get the pointers
193	    int8_t* ptr_input_data;
194	
195	    float* ptr_out_boxes_x;
196	    float* ptr_out_boxes_y;
197	    float* ptr_out_boxes_w;
198	    float* ptr_out_boxes_h;
199	    int* ptr_out_cls;
200	    float* ptr_out_score;
201	    int* ptr_out_box_num;
202	    
203	    OCL_CHECK(err,
204	              ptr_input_data = (int8_t*)q.enqueueMapBuffer(input_data, CL_TRUE, CL_MAP_WRITE, 0, big_int_size_in_bytes, NULL, NULL, &err));
205	    OCL_CHECK(err, 
206	              ptr_out_boxes_x = (float*)q.enqueueMapBuffer(out_boxes_x, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
207	    OCL_CHECK(err, 
208	              ptr_out_boxes_y = (float*)q.enqueueMapBuffer(out_boxes_y, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
209	    OCL_CHECK(err, 
210	              ptr_out_boxes_w = (float*)q.enqueueMapBuffer(out_boxes_w, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
211	    OCL_CHECK(err, 
212	              ptr_out_boxes_h = (float*)q.enqueueMapBuffer(out_boxes_h, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
213	    OCL_CHECK(err, 
214	              ptr_out_cls = (int*)q.enqueueMapBuffer(out_cls, CL_TRUE, CL_MAP_READ, 0, int_size_in_bytes, NULL, NULL, &err));
215	    OCL_CHECK(err, 
216	              ptr_out_score = (float*)q.enqueueMapBuffer(out_score, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
217	    OCL_CHECK(err, 
218	              ptr_out_box_num = (int*)q.enqueueMapBuffer(out_box_num, CL_TRUE, CL_MAP_READ, 0, int_size_in_bytes, NULL, NULL, &err));
219	
220	    // Loop over layers and process each
221	    for (size_t layer = 0; layer < num_layers; ++layer) {
222	        // Populate input data
223	        int total_size = feat_layer_sizes[layer] * feat_layer_sizes[layer] * output_dim;
224	        if (dataFileLoaded) {
225	            if (layer >= file_data.size()) {
226	                std::cerr << "ERROR: Not enough data arrays in file for layer " << layer << std::endl;
227	                return EXIT_FAILURE;
228	            }
229	            const std::vector<int8_t>& layer_data = file_data[layer];
230	            if (layer_data.size() < total_size) {
231	                std::cerr << "ERROR: Data array size " << layer_data.size() << " is less than expected " << total_size << " for layer " << layer << std::endl;
232	                return EXIT_FAILURE;
233	            }
234	            for (int i = 0; i < total_size; i++) {
235	                ptr_input_data[i] = layer_data[i];
236	            }
237	
238	        } else {
239	            for (int i = 0; i < total_size; i++) {
240	                ptr_input_data[i] = (i % 127) - 63;  // simple pattern
241	            }
242	        }
243	        // Set the scalar kernel args (overwrite previous values)
244	        int feat_layer_size  = feat_layer_sizes[layer];
245	        float feat_layer_stride  = feat_layer_strides[layer];
246	        OCL_CHECK(err, err = krnl_decode.setArg(layer_size_arg_index, feat_layer_size));
247	        OCL_CHECK(err, err = krnl_decode.setArg(layer_stride_arg_index, feat_layer_stride));
248	
249	        // Migrate input_data (host->device)
250	        OCL_CHECK(err, err = q.enqueueMigrateMemObjects({ input_data }, 0, nullptr, &evt_write));
251	
252	        // Launch the Kernel
253	        OCL_CHECK(err, err = q.enqueueTask(krnl_decode, nullptr, &evt_kernel));
254	
255	        // Retrieve output data (device->host)
256	        OCL_CHECK(err, q.enqueueMigrateMemObjects({out_boxes_x,out_boxes_y,out_boxes_w,out_boxes_h,out_cls,out_score,out_box_num}, CL_MIGRATE_MEM_OBJECT_HOST, nullptr, &evt_read));
257	
258	        OCL_CHECK(err, q.finish());
259	    
260	        if profile_cl {
261	            // Helper to read profiling times
262	            auto get_ns = [&](const cl::Event &e, cl_profiling_info info) -> cl_ulong {
263	                return e.getProfilingInfo<cl_ulong>(info, &prof_err);
264	            };
265	
266	            // Get start/end timestamps (nanoseconds)
267	            cl_ulong write_start = get_ns(evt_write, CL_PROFILING_COMMAND_START);
268	            cl_ulong write_end   = get_ns(evt_write, CL_PROFILING_COMMAND_END);
269	
270	            cl_ulong kernel_start = get_ns(evt_kernel, CL_PROFILING_COMMAND_START);
271	            cl_ulong kernel_end   = get_ns(evt_kernel, CL_PROFILING_COMMAND_END);
272	
273	            cl_ulong read_start = get_ns(evt_read, CL_PROFILING_COMMAND_START);
274	            cl_ulong read_end   = get_ns(evt_read, CL_PROFILING_COMMAND_END);
275	
276	            // Compute durations
277	            double write_ns  = double(write_end)  - double(write_start);
278	            double kernel_ns = double(kernel_end) - double(kernel_start);
279	            double read_ns   = double(read_end)   - double(read_start);
280	
281	            printf("Host->Device (write) time:  %.3f ms (% .0f ns)\n", write_ns/1e6, write_ns);
