#define OCL_CHECK(error, call)                                                                   \
    call;                                                                                        \
    if (error != CL_SUCCESS) {                                                                   \
        printf("%s:%d Error calling " #call ", error code is: %d\n", __FILE__, __LINE__, error); \
        exit(EXIT_FAILURE);                                                                      \
    }

#include "decode.h"
#include <fstream>
#include <iostream>
#include <stdlib.h>

static const int DATA_SIZE = 2048;
static const int MAX_FEATURE_SIZE = 2680000; // max size for 200x200 layer with output_dim=67

static const std::string error_message =
    "ERROR: Result mismatch:\n"
    "i = %d CPU result = %d Device result = %d\n";


std::vector<std::vector<int8_t>> loadDataFile(const std::string& filename) {
    std::ifstream infile(filename);
    if (!infile) {
        throw std::runtime_error("ERROR: Cannot open data file: " + filename);
    }

    std::vector<std::vector<int8_t>> data;
    std::string line;

    while (std::getline(infile, line)) {
        std::istringstream iss(line);
        std::vector<int8_t> row;
        int8_t value;
        int tmp;
        while (iss >> tmp) row.push_back(static_cast<int8_t>(tmp));

        if (!row.empty()) {
            data.push_back(row);
        }
    }

    return data;
}


int main(int argc, char* argv[]) {
    // TARGET_DEVICE macro needs to be passed from gcc command line
    if (argc < 2 || argc > 3) {
        std::cout << "ERROR: Usage: " << argv[0] << " <xclbin> [data_file]" << std::endl;
        return EXIT_FAILURE;
    }

    std::string xclbinFilename = argv[1];
    std::cout << "INFO: Running decode kernel " << xclbinFilename << std::endl;

    bool dataFileLoaded = false;                // Flag for whether data file is loaded
    std::vector<std::vector<int8_t>> file_data;       // Storage for loaded data
    // Load feature maps output data from file if provided
    if (argc == 3) {
        std::string data_file = argv[2];
        try {
            file_data = loadDataFile(data_file);
            dataFileLoaded = true;
            std::cout << "INFO: Loaded " << file_data.size() << " arrays from file: " << data_file << std::endl;

        } catch (const std::exception& e) {
            std::cerr << "ERROR: " << e.what() << std::endl;
            return EXIT_FAILURE;
        }
    } else {
        std::cout << "INFO: No data file provided" << std::endl;
    }

    // Compute the size of array in bytes
    size_t big_int_size_in_bytes = MAX_FEATURE_SIZE * sizeof(int8_t);
    size_t int_size_in_bytes = DATA_SIZE * sizeof(int);
    size_t float_size_in_bytes = DATA_SIZE * sizeof(float);
    size_t pragma_int_size_in_bytes = 16 * sizeof(int);
    size_t pragma_float_size_in_bytes = 16 * sizeof(float);

    std::vector<cl::Device> devices;
    cl_int err;
    cl::Context context;
    cl::CommandQueue q;
    cl::Kernel krnl_decode;
    cl::Program program;
    std::vector<cl::Platform> platforms;
    bool found_device = false;
    bool profile_cl = false;
    cl::Event evt_write;   // host -> device copy (migrate in)
    cl::Event evt_kernel;  // kernel run
    cl::Event evt_read;    // device -> host copy (migrate out)
    cl_int prof_err;

    // traversing all Platforms To find Xilinx Platform and targeted
    // Device in Xilinx Platform
    cl::Platform::get(&platforms);
    for (size_t i = 0; (i < platforms.size()) && (found_device == false); i++) {
        cl::Platform platform = platforms[i];
        std::string platformName = platform.getInfo<CL_PLATFORM_NAME>();
        if (platformName == "Xilinx") {
            devices.clear();
            platform.getDevices(CL_DEVICE_TYPE_ACCELERATOR, &devices);
            if (devices.size()) {
                found_device = true;
                break;
            }
        }
    }
    if (found_device == false) {
        std::cout << "Error: Unable to find Target Device " << std::endl;
        return EXIT_FAILURE;
    }

    std::cout << "INFO: Reading " << xclbinFilename << std::endl;
    FILE* fp;
    if ((fp = fopen(xclbinFilename.c_str(), "r")) == nullptr) {
        printf("ERROR: %s xclbin not available please build\n", xclbinFilename.c_str());
        exit(EXIT_FAILURE);
    }
    // Load xclbin
    std::cout << "Loading: '" << xclbinFilename << "'\n";
    std::ifstream bin_file(xclbinFilename, std::ifstream::binary);
    bin_file.seekg(0, bin_file.end);
    unsigned nb = bin_file.tellg();
    bin_file.seekg(0, bin_file.beg);
    char* buf = new char[nb];
    bin_file.read(buf, nb);

    // Creating Program from Binary File
    cl::Program::Binaries bins;
    bins.push_back({buf, nb});
    bool valid_device = false;
    for (unsigned int i = 0; i < devices.size(); i++) {
        auto device = devices[i];
        // Creating Context and Command Queue for selected Device
        OCL_CHECK(err, context = cl::Context(device, nullptr, nullptr, nullptr, &err));
        OCL_CHECK(err, q = cl::CommandQueue(context, device, CL_QUEUE_PROFILING_ENABLE, &err));
        std::cout << "Trying to program device[" << i << "]: " << device.getInfo<CL_DEVICE_NAME>() << std::endl;
        cl::Program program(context, {device}, bins, nullptr, &err);
        if (err != CL_SUCCESS) {
            std::cout << "Failed to program device[" << i << "] with xclbin file!\n";
        } else {
            std::cout << "Device[" << i << "]: program successful!\n";
            OCL_CHECK(err, krnl_decode = cl::Kernel(program, "decode_krnl", &err));
            valid_device = true;
            break; // we break because we found a valid device
        }
    }
    if (!valid_device) {
        std::cout << "Failed to program any device found, exit!\n";
        exit(EXIT_FAILURE);
    }

    const int num_layers   = 4;
    const int num_classes  = 3;
    const int output_dim   = num_classes + 64;
    const float conf_thresh = 0.25f;
    const int max_boxes_num = 2048;
    const int feat_layer_sizes[num_layers] = {200, 100, 50, 25};
    const float feat_layer_strides[num_layers] = {4.0f, 8.0f, 16.0f, 32.0f};

    // Input buffers
    OCL_CHECK(err, cl::Buffer input_data(context, CL_MEM_READ_ONLY, big_int_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer layer_size(context, CL_MEM_READ_ONLY, pragma_int_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer layer_stride(context, CL_MEM_READ_ONLY, pragma_float_size_in_bytes, NULL, &err));

    // Output return buffer
    OCL_CHECK(err, cl::Buffer out_boxes_x(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer out_boxes_y(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));    
    OCL_CHECK(err, cl::Buffer out_boxes_w(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer out_boxes_h(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer out_cls(context, CL_MEM_WRITE_ONLY, int_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer out_score(context, CL_MEM_WRITE_ONLY, float_size_in_bytes, NULL, &err));
    OCL_CHECK(err, cl::Buffer out_box_num(context, CL_MEM_WRITE_ONLY, int_size_in_bytes, NULL, &err));

    // // set the kernel Arguments
    int narg = 0;
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, input_data));
    // OCL_CHECK(err, err = krnl_decode.setArg(narg++, layer_size));
    // OCL_CHECK(err, err = krnl_decode.setArg(narg++, layer_stride));
    int layer_size_arg_index = narg++;      // remember index for layer_size
    int layer_stride_arg_index = narg++;    // remember index for layer_stride
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_x));    
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_y));  
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_w));    
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_boxes_h));  
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_cls));    
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_score));    
    OCL_CHECK(err, err = krnl_decode.setArg(narg++, out_box_num));

    // We then need to map our OpenCL buffers to get the pointers
    int8_t* ptr_input_data;

    float* ptr_out_boxes_x;
    float* ptr_out_boxes_y;
    float* ptr_out_boxes_w;
    float* ptr_out_boxes_h;
    int* ptr_out_cls;
    float* ptr_out_score;
    int* ptr_out_box_num;

    OCL_CHECK(err,
              ptr_input_data = (int8_t*)q.enqueueMapBuffer(input_data, CL_TRUE, CL_MAP_WRITE, 0, big_int_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_boxes_x = (float*)q.enqueueMapBuffer(out_boxes_x, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_boxes_y = (float*)q.enqueueMapBuffer(out_boxes_y, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_boxes_w = (float*)q.enqueueMapBuffer(out_boxes_w, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_boxes_h = (float*)q.enqueueMapBuffer(out_boxes_h, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_cls = (int*)q.enqueueMapBuffer(out_cls, CL_TRUE, CL_MAP_READ, 0, int_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_score = (float*)q.enqueueMapBuffer(out_score, CL_TRUE, CL_MAP_READ, 0, float_size_in_bytes, NULL, NULL, &err));
    OCL_CHECK(err, 
              ptr_out_box_num = (int*)q.enqueueMapBuffer(out_box_num, CL_TRUE, CL_MAP_READ, 0, int_size_in_bytes, NULL, NULL, &err));

    // Loop over layers and process each
    for (size_t layer = 0; layer < num_layers; ++layer) {
        // Populate input data
        int total_size = feat_layer_sizes[layer] * feat_layer_sizes[layer] * output_dim;
        if (dataFileLoaded) {
            if (layer >= file_data.size()) {
                std::cerr << "ERROR: Not enough data arrays in file for layer " << layer << std::endl;
                return EXIT_FAILURE;
            }
            const std::vector<int8_t>& layer_data = file_data[layer];
            if (layer_data.size() < total_size) {
                std::cerr << "ERROR: Data array size " << layer_data.size() << " is less than expected " << total_size << " for layer " << layer << std::endl;
                return EXIT_FAILURE;
            }
            for (int i = 0; i < total_size; i++) {
                ptr_input_data[i] = layer_data[i];
            }

        } else {
            for (int i = 0; i < total_size; i++) {
                ptr_input_data[i] = (i % 127) - 63;  // simple pattern
            }
        }
        // Set the scalar kernel args (overwrite previous values)
        int feat_layer_size  = feat_layer_sizes[layer];
        float feat_layer_stride  = feat_layer_strides[layer];
        OCL_CHECK(err, err = krnl_decode.setArg(layer_size_arg_index, feat_layer_size));
        OCL_CHECK(err, err = krnl_decode.setArg(layer_stride_arg_index, feat_layer_stride));

        // Migrate input_data (host->device)
        OCL_CHECK(err, err = q.enqueueMigrateMemObjects({ input_data }, 0, nullptr, &evt_write));

        // Launch the Kernel
        OCL_CHECK(err, err = q.enqueueTask(krnl_decode, nullptr, &evt_kernel));

        // Retrieve output data (device->host)
        OCL_CHECK(err, q.enqueueMigrateMemObjects({out_boxes_x,out_boxes_y,out_boxes_w,out_boxes_h,out_cls,out_score,out_box_num}, CL_MIGRATE_MEM_OBJECT_HOST, nullptr, &evt_read));

        OCL_CHECK(err, q.finish());

        if profile_cl {
            // Helper to read profiling times
            auto get_ns = [&](const cl::Event &e, cl_profiling_info info) -> cl_ulong {
                return e.getProfilingInfo<cl_ulong>(info, &prof_err);
            };

            // Get start/end timestamps (nanoseconds)
            cl_ulong write_start = get_ns(evt_write, CL_PROFILING_COMMAND_START);
            cl_ulong write_end   = get_ns(evt_write, CL_PROFILING_COMMAND_END);

            cl_ulong kernel_start = get_ns(evt_kernel, CL_PROFILING_COMMAND_START);
            cl_ulong kernel_end   = get_ns(evt_kernel, CL_PROFILING_COMMAND_END);

            cl_ulong read_start = get_ns(evt_read, CL_PROFILING_COMMAND_START);
            cl_ulong read_end   = get_ns(evt_read, CL_PROFILING_COMMAND_END);

            // Compute durations
            double write_ns  = double(write_end)  - double(write_start);
            double kernel_ns = double(kernel_end) - double(kernel_start);
            double read_ns   = double(read_end)   - double(read_start);

            printf("Host->Device (write) time:  %.3f ms (% .0f ns)\n", write_ns/1e6, write_ns);
            printf("Kernel execution time:      %.3f ms (% .0f ns)\n", kernel_ns/1e6, kernel_ns);
            printf("Device->Host (read) time:   %.3f ms (% .0f ns)\n", read_ns/1e6, read_ns);
            printf("Total (write+kernel+read):  %.3f ms\n", (write_ns+kernel_ns+read_ns)/1e6);
        }
    }
}

